   399→) -> anyhow::Result<Vec<lsp_types::TextEdit>> {
   400→    let _p = tracing::info_span!("handle_join_lines").entered();
   401→
   402→    let file_id = try_default!(from_proto::file_id(&snap, &params.text_document.uri)?);
   403→    let config = snap.config.join_lines();
   404→    let line_index = snap.file_line_index(file_id)?;
   405→
   406→    let mut res = TextEdit::default();
   407→    for range in params.ranges {
   408→        let range = from_proto::text_range(&line_index, range)?;
   409→        let edit = snap.analysis.join_lines(&config, FileRange { file_id, range })?;
   410→        match res.union(edit) {
   411→            Ok(()) => (),
   412→            Err(_edit) => {
   413→                // just ignore overlapping edits
   414→            }
   415→        }
   416→    }
   417→
   418→    Ok(to_proto::text_edit_vec(&line_index, res))
   419→}
