   643→pub(crate) fn handle_workspace_symbol(
   644→    snap: GlobalStateSnapshot,
   645→    params: WorkspaceSymbolParams,
   646→) -> anyhow::Result<Option<lsp_types::WorkspaceSymbolResponse>> {
   647→    let _p = tracing::info_span!("handle_workspace_symbol").entered();
   648→
   649→    let config = snap.config.workspace_symbol(None);
   650→    let (all_symbols, libs) = decide_search_scope_and_kind(&params, &config);
   651→
   652→    let query = {
   653→        let query: String = params.query.chars().filter(|&c| c != '#' && c != '*').collect();
   654→        let mut q = Query::new(query);
   655→        if !all_symbols {
   656→            q.only_types();
   657→        }
   658→        if libs {
   659→            q.libs();
   660→        }
   661→        if config.search_exclude_imports {
   662→            q.exclude_imports();
   663→        }
   664→        q
   665→    };
   666→    let mut res = exec_query(&snap, query, config.search_limit)?;
   667→    if res.is_empty() && !all_symbols {
   668→        res = exec_query(&snap, Query::new(params.query), config.search_limit)?;
   669→    }
   670→
   671→    return Ok(Some(lsp_types::WorkspaceSymbolResponse::Nested(res)));
   672→
   673→    fn decide_search_scope_and_kind(
   674→        params: &WorkspaceSymbolParams,
   675→        config: &WorkspaceSymbolConfig,
   676→    ) -> (bool, bool) {
   677→        // Support old-style parsing of markers in the query.
   678→        let mut all_symbols = params.query.contains('#');
   679→        let mut libs = params.query.contains('*');
   680→
   681→        // If no explicit marker was set, check request params. If that's also empty
   682→        // use global config.
   683→        if !all_symbols {
   684→            let search_kind = match params.search_kind {
   685→                Some(ref search_kind) => search_kind,
   686→                None => &config.search_kind,
   687→            };
   688→            all_symbols = match search_kind {
   689→                lsp_ext::WorkspaceSymbolSearchKind::OnlyTypes => false,
   690→                lsp_ext::WorkspaceSymbolSearchKind::AllSymbols => true,
   691→            }
   692→        }
   693→
   694→        if !libs {
   695→            let search_scope = match params.search_scope {
   696→                Some(ref search_scope) => search_scope,
   697→                None => &config.search_scope,
   698→            };
   699→            libs = match search_scope {
   700→                lsp_ext::WorkspaceSymbolSearchScope::Workspace => false,
   701→                lsp_ext::WorkspaceSymbolSearchScope::WorkspaceAndDependencies => true,
   702→            }
   703→        }
   704→
   705→        (all_symbols, libs)
   706→    }
   707→
   708→    fn exec_query(
   709→        snap: &GlobalStateSnapshot,
   710→        query: Query,
   711→        limit: usize,
   712→    ) -> anyhow::Result<Vec<lsp_types::WorkspaceSymbol>> {
   713→        let mut res = Vec::new();
   714→        for nav in snap.analysis.symbol_search(query, limit)? {
   715→            let container_name = nav.container_name.as_ref().map(|v| v.to_string());
   716→
   717→            let info = lsp_types::WorkspaceSymbol {
   718→                name: match &nav.alias {
   719→                    Some(alias) => format!("{} (alias for {})", alias, nav.name),
   720→                    None => format!("{}", nav.name),
   721→                },
   722→                kind: nav
   723→                    .kind
   724→                    .map(to_proto::symbol_kind)
   725→                    .unwrap_or(lsp_types::SymbolKind::VARIABLE),
   726→                // FIXME: Set deprecation
   727→                tags: None,
   728→                container_name,
   729→                location: lsp_types::OneOf::Left(to_proto::location_from_nav(snap, nav)?),
   730→                data: None,
   731→            };
   732→            res.push(info);
   733→        }
   734→        Ok(res)
   735→    }
   736→}
