   738→pub(crate) fn handle_will_rename_files(
   739→    snap: GlobalStateSnapshot,
   740→    params: lsp_types::RenameFilesParams,
   741→) -> anyhow::Result<Option<lsp_types::WorkspaceEdit>> {
   742→    let _p = tracing::info_span!("handle_will_rename_files").entered();
   743→
   744→    let source_changes: Vec<SourceChange> = params
   745→        .files
   746→        .into_iter()
   747→        .filter_map(|file_rename| {
   748→            let from = Url::parse(&file_rename.old_uri).ok()?;
   749→            let to = Url::parse(&file_rename.new_uri).ok()?;
   750→
   751→            let from_path = from.to_file_path().ok()?;
   752→            let to_path = to.to_file_path().ok()?;
   753→
   754→            // Limit to single-level moves for now.
   755→            match (from_path.parent(), to_path.parent()) {
   756→                (Some(p1), Some(p2)) if p1 == p2 => {
   757→                    if from_path.is_dir() {
   758→                        // add '/' to end of url -- from `file://path/to/folder` to `file://path/to/folder/`
   759→                        let mut old_folder_name = from_path.file_stem()?.to_str()?.to_owned();
   760→                        old_folder_name.push('/');
   761→                        let from_with_trailing_slash = from.join(&old_folder_name).ok()?;
   762→
   763→                        let imitate_from_url = from_with_trailing_slash.join("mod.rs").ok()?;
   764→                        let new_file_name = to_path.file_name()?.to_str()?;
   765→                        Some((
   766→                            snap.url_to_file_id(&imitate_from_url).ok()?,
   767→                            new_file_name.to_owned(),
   768→                        ))
   769→                    } else {
   770→                        let old_name = from_path.file_stem()?.to_str()?;
   771→                        let new_name = to_path.file_stem()?.to_str()?;
   772→                        match (old_name, new_name) {
   773→                            ("mod", _) => None,
   774→                            (_, "mod") => None,
   775→                            _ => Some((snap.url_to_file_id(&from).ok()?, new_name.to_owned())),
   776→                        }
   777→                    }
   778→                }
   779→                _ => None,
   780→            }
   781→        })
   782→        .filter_map(|(file_id, new_name)| {
   783→            snap.analysis.will_rename_file(file_id?, &new_name).ok()?
   784→        })
   785→        .collect();
   786→
   787→    // Drop file system edits since we're just renaming things on the same level
   788→    let mut source_changes = source_changes.into_iter();
   789→    let mut source_change = source_changes.next().unwrap_or_default();
   790→    source_change.file_system_edits.clear();
   791→    // no collect here because we want to merge text edits on same file ids
   792→    source_change.extend(source_changes.flat_map(|it| it.source_file_edits));
   793→    if source_change.source_file_edits.is_empty() {
   794→        Ok(None)
   795→    } else {
   796→        Ok(Some(to_proto::workspace_edit(&snap, source_change)?))
   797→    }
   798→}
