   866→pub(crate) fn handle_parent_module(
   867→    snap: GlobalStateSnapshot,
   868→    params: lsp_types::TextDocumentPositionParams,
   869→) -> anyhow::Result<Option<lsp_types::GotoDefinitionResponse>> {
   870→    let _p = tracing::info_span!("handle_parent_module").entered();
   871→    if let Ok(file_path) = &params.text_document.uri.to_file_path() {
   872→        if file_path.file_name().unwrap_or_default() == "Cargo.toml" {
   873→            // search workspaces for parent packages or fallback to workspace root
   874→            let abs_path_buf = match Utf8PathBuf::from_path_buf(file_path.to_path_buf())
   875→                .ok()
   876→                .map(AbsPathBuf::try_from)
   877→            {
   878→                Some(Ok(abs_path_buf)) => abs_path_buf,
   879→                _ => return Ok(None),
   880→            };
   881→
   882→            let manifest_path = match ManifestPath::try_from(abs_path_buf).ok() {
   883→                Some(manifest_path) => manifest_path,
   884→                None => return Ok(None),
   885→            };
   886→
   887→            let links: Vec<LocationLink> = snap
   888→                .workspaces
   889→                .iter()
   890→                .filter_map(|ws| match &ws.kind {
   891→                    ProjectWorkspaceKind::Cargo { cargo, .. }
   892→                    | ProjectWorkspaceKind::DetachedFile { cargo: Some((cargo, _, _)), .. } => {
   893→                        cargo.parent_manifests(&manifest_path)
   894→                    }
   895→                    _ => None,
   896→                })
   897→                .flatten()
   898→                .map(|parent_manifest_path| LocationLink {
   899→                    origin_selection_range: None,
   900→                    target_uri: to_proto::url_from_abs_path(&parent_manifest_path),
   901→                    target_range: Range::default(),
   902→                    target_selection_range: Range::default(),
   903→                })
   904→                .collect::<_>();
   905→            return Ok(Some(links.into()));
   906→        }
   907→
   908→        // check if invoked at the crate root
   909→        let file_id = try_default!(from_proto::file_id(&snap, &params.text_document.uri)?);
   910→        let crate_id = match snap.analysis.crates_for(file_id)?.first() {
   911→            Some(&crate_id) => crate_id,
   912→            None => return Ok(None),
   913→        };
   914→        let cargo_spec = match TargetSpec::for_file(&snap, file_id)? {
   915→            Some(TargetSpec::Cargo(it)) => it,
   916→            Some(TargetSpec::ProjectJson(_)) | None => return Ok(None),
   917→        };
   918→
   919→        if snap.analysis.crate_root(crate_id)? == file_id {
   920→            let cargo_toml_url = to_proto::url_from_abs_path(&cargo_spec.cargo_toml);
