   951→pub(crate) fn handle_runnables(
   952→    snap: GlobalStateSnapshot,
   953→    params: lsp_ext::RunnablesParams,
   954→) -> anyhow::Result<Vec<lsp_ext::Runnable>> {
   955→    let _p = tracing::info_span!("handle_runnables").entered();
   956→    let file_id = try_default!(from_proto::file_id(&snap, &params.text_document.uri)?);
   957→    let source_root = snap.analysis.source_root_id(file_id).ok();
   958→    let line_index = snap.file_line_index(file_id)?;
   959→    let offset = params.position.and_then(|it| from_proto::offset(&line_index, it).ok());
   960→    let target_spec = TargetSpec::for_file(&snap, file_id)?;
   961→
   962→    let mut res = Vec::new();
   963→    for runnable in snap.analysis.runnables(file_id)? {
   964→        if should_skip_for_offset(&runnable, offset)
   965→            || should_skip_target(&runnable, target_spec.as_ref())
   966→        {
   967→            continue;
   968→        }
   969→
   970→        let update_test = runnable.update_test;
   971→        if let Some(mut runnable) = to_proto::runnable(&snap, runnable)? {
   972→            if let Some(runnable) = to_proto::make_update_runnable(&runnable, update_test) {
   973→                res.push(runnable);
   974→            }
   975→
   976→            if let lsp_ext::RunnableArgs::Cargo(r) = &mut runnable.args {
   977→                if let Some(TargetSpec::Cargo(CargoTargetSpec {
   978→                    sysroot_root: Some(sysroot_root),
   979→                    ..
   980→                })) = &target_spec
   981→                {
   982→                    r.environment.insert("RUSTC_TOOLCHAIN".to_owned(), sysroot_root.to_string());
   983→                }
   984→            };
   985→
   986→            res.push(runnable);
   987→        }
   988→    }
   989→
   990→    // Add `cargo check` and `cargo test` for all targets of the whole package
   991→    let config = snap.config.runnables(source_root);
   992→    match target_spec {
   993→        Some(TargetSpec::Cargo(spec)) => {
   994→            let is_crate_no_std = snap.analysis.is_crate_no_std(spec.crate_id)?;
   995→            for cmd in ["check", "run", "test"] {
   996→                if cmd == "run" && spec.target_kind != TargetKind::Bin {
   997→                    continue;
   998→                }
   999→                let cwd = if cmd != "test" || spec.target_kind == TargetKind::Bin {
  1000→                    spec.workspace_root.clone()
  1001→                } else {
  1002→                    spec.cargo_toml.parent().to_path_buf()
  1003→                };
  1004→                let mut cargo_args =
  1005→                    vec![cmd.to_owned(), "--package".to_owned(), spec.package.clone()];
  1006→                let all_targets = cmd != "run" && !is_crate_no_std;
  1007→                if all_targets {
  1008→                    cargo_args.push("--all-targets".to_owned());
  1009→                }
  1010→                cargo_args.extend(config.cargo_extra_args.iter().cloned());
  1011→                res.push(lsp_ext::Runnable {
  1012→                    label: format!(
  1013→                        "cargo {cmd} -p {}{all_targets}",
  1014→                        spec.package,
  1015→                        all_targets = if all_targets { " --all-targets" } else { "" }
  1016→                    ),
  1017→                    location: None,
  1018→                    kind: lsp_ext::RunnableKind::Cargo,
  1019→                    args: lsp_ext::RunnableArgs::Cargo(lsp_ext::CargoRunnableArgs {
  1020→                        workspace_root: Some(spec.workspace_root.clone().into()),
  1021→                        cwd: cwd.into(),
  1022→                        override_cargo: config.override_cargo.clone(),
  1023→                        cargo_args,
  1024→                        executable_args: Vec::new(),
  1025→                        environment: spec
  1026→                            .sysroot_root
  1027→                            .as_ref()
  1028→                            .map(|root| ("RUSTC_TOOLCHAIN".to_owned(), root.to_string()))
  1029→                            .into_iter()
  1030→                            .collect(),
  1031→                    }),
  1032→                })
  1033→            }
  1034→        }
  1035→        Some(TargetSpec::ProjectJson(_)) => {}
  1036→        None => {
  1037→            if !snap.config.linked_or_discovered_projects().is_empty() {
  1038→                if let Some(path) = snap.file_id_to_file_path(file_id).parent() {
  1039→                    let mut cargo_args = vec!["check".to_owned(), "--workspace".to_owned()];
  1040→                    cargo_args.extend(config.cargo_extra_args.iter().cloned());
  1041→                    res.push(lsp_ext::Runnable {
  1042→                        label: "cargo check --workspace".to_owned(),
  1043→                        location: None,
  1044→                        kind: lsp_ext::RunnableKind::Cargo,
  1045→                        args: lsp_ext::RunnableArgs::Cargo(lsp_ext::CargoRunnableArgs {
  1046→                            workspace_root: None,
  1047→                            cwd: path.as_path().unwrap().to_path_buf().into(),
  1048→                            override_cargo: config.override_cargo,
  1049→                            cargo_args,
  1050→                            executable_args: Vec::new(),
  1051→                            environment: Default::default(),
  1052→                        }),
  1053→                    });
  1054→                };
  1055→            }
  1056→        }
  1057→    }
  1058→    Ok(res)
  1059→}
