  1061→fn should_skip_for_offset(runnable: &Runnable, offset: Option<TextSize>) -> bool {
  1062→    match offset {
  1063→        None => false,
  1064→        _ if matches!(&runnable.kind, RunnableKind::TestMod { .. }) => false,
  1065→        Some(offset) => !runnable.nav.full_range.contains_inclusive(offset),
  1066→    }
  1067→}
