  1087→pub(crate) fn handle_completion(
  1088→    snap: GlobalStateSnapshot,
  1089→    lsp_types::CompletionParams {
  1090→        text_document_position,
  1091→        context,
  1092→        ..
  1093→    }: lsp_types::CompletionParams,
  1094→) -> anyhow::Result<Option<lsp_types::CompletionResponse>> {
  1095→    let _p = tracing::info_span!("handle_completion").entered();
  1096→    let mut position =
  1097→        try_default!(from_proto::file_position(&snap, text_document_position.clone())?);
  1098→    let line_index = snap.file_line_index(position.file_id)?;
  1099→    let completion_trigger_character =
  1100→        context.and_then(|ctx| ctx.trigger_character).and_then(|s| s.chars().next());
  1101→
  1102→    let source_root = snap.analysis.source_root_id(position.file_id)?;
  1103→    let completion_config = &snap.config.completion(Some(source_root));
  1104→    // FIXME: We should fix up the position when retrying the cancelled request instead
  1105→    position.offset = position.offset.min(line_index.index.len());
  1106→    let items = match snap.analysis.completions(
  1107→        completion_config,
  1108→        position,
  1109→        completion_trigger_character,
  1110→    )? {
  1111→        None => return Ok(None),
  1112→        Some(items) => items,
  1113→    };
  1114→
  1115→    let items = to_proto::completion_items(
  1116→        &snap.config,
  1117→        &completion_config.fields_to_resolve,
  1118→        &line_index,
  1119→        snap.file_version(position.file_id),
  1120→        text_document_position,
  1121→        completion_trigger_character,
  1122→        items,
  1123→    );
  1124→
  1125→    let completion_list = lsp_types::CompletionList { is_incomplete: true, items };
  1126→    Ok(Some(completion_list.into()))
  1127→}
