  1129→pub(crate) fn handle_completion_resolve(
  1130→    snap: GlobalStateSnapshot,
  1131→    mut original_completion: CompletionItem,
  1132→) -> anyhow::Result<CompletionItem> {
  1133→    let _p = tracing::info_span!("handle_completion_resolve").entered();
  1134→
  1135→    if !all_edits_are_disjoint(&original_completion, &[]) {
  1136→        return Err(invalid_params_error(
  1137→            "Received a completion with overlapping edits, this is not LSP-compliant".to_owned(),
  1138→        )
  1139→        .into());
  1140→    }
  1141→
  1142→    let Some(data) = original_completion.data.take() else {
  1143→        return Ok(original_completion);
  1144→    };
  1145→
  1146→    let resolve_data: lsp_ext::CompletionResolveData = serde_json::from_value(data)?;
  1147→
  1148→    let file_id = from_proto::file_id(&snap, &resolve_data.position.text_document.uri)?
  1149→        .expect("we never provide completions for excluded files");
  1150→    let line_index = snap.file_line_index(file_id)?;
  1151→    // FIXME: We should fix up the position when retrying the cancelled request instead
  1152→    let Ok(offset) = from_proto::offset(&line_index, resolve_data.position.position) else {
  1153→        return Ok(original_completion);
  1154→    };
  1155→    let source_root = snap.analysis.source_root_id(file_id)?;
  1156→
  1157→    let mut forced_resolve_completions_config = snap.config.completion(Some(source_root));
  1158→    forced_resolve_completions_config.fields_to_resolve = CompletionFieldsToResolve::empty();
  1159→
  1160→    let position = FilePosition { file_id, offset };
  1161→    let Some(completions) = snap.analysis.completions(
  1162→        &forced_resolve_completions_config,
  1163→        position,
  1164→        resolve_data.trigger_character,
  1165→    )?
  1166→    else {
  1167→        return Ok(original_completion);
  1168→    };
  1169→    let Ok(resolve_data_hash) = BASE64_STANDARD.decode(resolve_data.hash) else {
  1170→        return Ok(original_completion);
  1171→    };
  1172→
  1173→    let Some(corresponding_completion) = completions.into_iter().find(|completion_item| {
  1174→        // Avoid computing hashes for items that obviously do not match
  1175→        // r-a might append a detail-based suffix to the label, so we cannot check for equality
  1176→        original_completion.label.starts_with(completion_item.label.primary.as_str())
  1177→            && resolve_data_hash == completion_item_hash(completion_item, resolve_data.for_ref)
  1178→    }) else {
  1179→        return Ok(original_completion);
  1180→    };
  1181→
  1182→    let mut resolved_completions = to_proto::completion_items(
  1183→        &snap.config,
  1184→        &forced_resolve_completions_config.fields_to_resolve,
  1185→        &line_index,
  1186→        snap.file_version(position.file_id),
  1187→        resolve_data.position,
  1188→        resolve_data.trigger_character,
  1189→        vec![corresponding_completion],
  1190→    );
  1191→    let Some(mut resolved_completion) = resolved_completions.pop() else {
  1192→        return Ok(original_completion);
  1193→    };
  1194→
  1195→    if !resolve_data.imports.is_empty() {
  1196→        let additional_edits = snap
  1197→            .analysis
  1198→            .resolve_completion_edits(
  1199→                &forced_resolve_completions_config,
  1200→                position,
  1201→                resolve_data.imports.into_iter().map(|import| import.full_import_path),
  1202→            )?
  1203→            .into_iter()
  1204→            .flat_map(|edit| edit.into_iter().map(|indel| to_proto::text_edit(&line_index, indel)))
  1205→            .collect::<Vec<_>>();
  1206→
  1207→        if !all_edits_are_disjoint(&resolved_completion, &additional_edits) {
  1208→            return Err(LspError::new(
  1209→                ErrorCode::InternalError as i32,
  1210→                "Import edit overlaps with the original completion edits, this is not LSP-compliant"
  1211→                    .into(),
  1212→            )
  1213→            .into());
  1214→        }
  1215→
  1216→        if let Some(original_additional_edits) = resolved_completion.additional_text_edits.as_mut()
  1217→        {
  1218→            original_additional_edits.extend(additional_edits)
  1219→        } else {
  1220→            resolved_completion.additional_text_edits = Some(additional_edits);
  1221→        }
  1222→    }
  1223→
  1224→    Ok(resolved_completion)
  1225→}
