  1312→pub(crate) fn handle_rename(
  1313→    snap: GlobalStateSnapshot,
  1314→    params: RenameParams,
  1315→) -> anyhow::Result<Option<WorkspaceEdit>> {
  1316→    let _p = tracing::info_span!("handle_rename").entered();
  1317→    let position = try_default!(from_proto::file_position(&snap, params.text_document_position)?);
  1318→
  1319→    let mut change =
  1320→        snap.analysis.rename(position, &params.new_name)?.map_err(to_proto::rename_error)?;
  1321→
  1322→    // this is kind of a hack to prevent double edits from happening when moving files
  1323→    // When a module gets renamed by renaming the mod declaration this causes the file to move
  1324→    // which in turn will trigger a WillRenameFiles request to the server for which we reply with a
  1325→    // a second identical set of renames, the client will then apply both edits causing incorrect edits
  1326→    // with this we only emit source_file_edits in the WillRenameFiles response which will do the rename instead
  1327→    // See https://github.com/microsoft/vscode-languageserver-node/issues/752 for more info
  1328→    if !change.file_system_edits.is_empty() && snap.config.will_rename() {
  1329→        change.source_file_edits.clear();
  1330→    }
  1331→
  1332→    let workspace_edit = to_proto::workspace_edit(&snap, change)?;
  1333→
  1334→    if let Some(lsp_types::DocumentChanges::Operations(ops)) =
  1335→        workspace_edit.document_changes.as_ref()
  1336→    {
  1337→        for op in ops {
  1338→            if let lsp_types::DocumentChangeOperation::Op(doc_change_op) = op {
  1339→                resource_ops_supported(&snap.config, resolve_resource_op(doc_change_op))?
  1340→            }
  1341→        }
  1342→    }
  1343→
  1344→    Ok(Some(workspace_edit))
  1345→}
