  1347→pub(crate) fn handle_references(
  1348→    snap: GlobalStateSnapshot,
  1349→    params: lsp_types::ReferenceParams,
  1350→) -> anyhow::Result<Option<Vec<Location>>> {
  1351→    let _p = tracing::info_span!("handle_references").entered();
  1352→    let position = try_default!(from_proto::file_position(&snap, params.text_document_position)?);
  1353→
  1354→    let exclude_imports = snap.config.find_all_refs_exclude_imports();
  1355→    let exclude_tests = snap.config.find_all_refs_exclude_tests();
  1356→
  1357→    let Some(refs) = snap.analysis.find_all_refs(position, None)? else {
  1358→        return Ok(None);
  1359→    };
  1360→
  1361→    let include_declaration = params.context.include_declaration;
  1362→    let locations = refs
  1363→        .into_iter()
  1364→        .flat_map(|refs| {
  1365→            let decl = if include_declaration {
  1366→                refs.declaration.map(|decl| FileRange {
  1367→                    file_id: decl.nav.file_id,
  1368→                    range: decl.nav.focus_or_full_range(),
  1369→                })
  1370→            } else {
  1371→                None
  1372→            };
  1373→            refs.references
  1374→                .into_iter()
  1375→                .flat_map(|(file_id, refs)| {
  1376→                    refs.into_iter()
  1377→                        .filter(|&(_, category)| {
  1378→                            (!exclude_imports || !category.contains(ReferenceCategory::IMPORT))
  1379→                                && (!exclude_tests || !category.contains(ReferenceCategory::TEST))
  1380→                        })
  1381→                        .map(move |(range, _)| FileRange { file_id, range })
  1382→                })
  1383→                .chain(decl)
  1384→        })
  1385→        .unique()
  1386→        .filter_map(|frange| to_proto::location(&snap, frange).ok())
  1387→        .collect();
  1388→
  1389→    Ok(Some(locations))
  1390→}
