  1415→
  1416→    if !snap.config.code_action_literals() {
  1417→        // We intentionally don't support command-based actions, as those either
  1418→        // require either custom client-code or server-initiated edits. Server
  1419→        // initiated edits break causality, so we avoid those.
  1420→        return Ok(None);
  1421→    }
  1422→
  1423→    let file_id = try_default!(from_proto::file_id(&snap, &params.text_document.uri)?);
  1424→    let line_index = snap.file_line_index(file_id)?;
  1425→    let frange = try_default!(from_proto::file_range(&snap, &params.text_document, params.range)?);
  1426→    let source_root = snap.analysis.source_root_id(file_id)?;
  1427→
  1428→    let mut assists_config = snap.config.assist(Some(source_root));
  1429→    assists_config.allowed = params
  1430→        .context
  1431→        .only
  1432→        .clone()
  1433→        .map(|it| it.into_iter().filter_map(from_proto::assist_kind).collect());
  1434→
  1435→    let mut res: Vec<lsp_ext::CodeAction> = Vec::new();
  1436→
  1437→    let code_action_resolve_cap = snap.config.code_action_resolve();
  1438→    let resolve = if code_action_resolve_cap {
  1439→        AssistResolveStrategy::None
  1440→    } else {
  1441→        AssistResolveStrategy::All
  1442→    };
  1443→    let assists = snap.analysis.assists_with_fixes(
  1444→        &assists_config,
  1445→        &snap.config.diagnostic_fixes(Some(source_root)),
  1446→        resolve,
  1447→        frange,
  1448→    )?;
  1449→    for (index, assist) in assists.into_iter().enumerate() {
  1450→        let resolve_data = if code_action_resolve_cap {
  1451→            Some((index, params.clone(), snap.file_version(file_id)))
  1452→        } else {
  1453→            None
  1454→        };
  1455→        let code_action = to_proto::code_action(&snap, assist, resolve_data)?;
  1456→
  1457→        // Check if the client supports the necessary `ResourceOperation`s.
  1458→        let changes = code_action.edit.as_ref().and_then(|it| it.document_changes.as_ref());
  1459→        if let Some(changes) = changes {
  1460→            for change in changes {
  1461→                if let lsp_ext::SnippetDocumentChangeOperation::Op(res_op) = change {
  1462→                    resource_ops_supported(&snap.config, resolve_resource_op(res_op))?
  1463→                }
  1464→            }
  1465→        }
  1466→
  1467→        res.push(code_action)
  1468→    }
  1469→
  1470→    // Fixes from `cargo check`.
  1471→    for fix in snap
  1472→        .check_fixes
  1473→        .iter()
  1474→        .flat_map(|it| it.values())
  1475→        .filter_map(|it| it.get(&frange.file_id))
  1476→        .flatten()
  1477→    {
  1478→        // FIXME: this mapping is awkward and shouldn't exist. Refactor
  1479→        // `snap.check_fixes` to not convert to LSP prematurely.
  1480→        let intersect_fix_range = fix
  1481→            .ranges
  1482→            .iter()
  1483→            .copied()
  1484→            .filter_map(|range| from_proto::text_range(&line_index, range).ok())
  1485→            .any(|fix_range| fix_range.intersect(frange.range).is_some());
  1486→        if intersect_fix_range {
  1487→            res.push(fix.action.clone());
  1488→        }
  1489→    }
  1490→
  1491→    Ok(Some(res))
  1492→}
  1493→
  1494→pub(crate) fn handle_code_action_resolve(
  1495→    snap: GlobalStateSnapshot,
  1496→    mut code_action: lsp_ext::CodeAction,
  1497→) -> anyhow::Result<lsp_ext::CodeAction> {
  1498→    let _p = tracing::info_span!("handle_code_action_resolve").entered();
  1499→    let Some(params) = code_action.data.take() else {
  1500→        return Ok(code_action);
  1501→    };
  1502→
  1503→    let file_id = from_proto::file_id(&snap, &params.code_action_params.text_document.uri)?
  1504→        .expect("we never provide code actions for excluded files");
  1505→    if snap.file_version(file_id) != params.version {
  1506→        return Err(invalid_params_error("stale code action".to_owned()).into());
  1507→    }
  1508→    let line_index = snap.file_line_index(file_id)?;
  1509→    let range = from_proto::text_range(&line_index, params.code_action_params.range)?;
  1510→    let frange = FileRange { file_id, range };
  1511→    let source_root = snap.analysis.source_root_id(file_id)?;
  1512→
  1513→    let mut assists_config = snap.config.assist(Some(source_root));
  1514→    assists_config.allowed = params
  1515→        .code_action_params
  1516→        .context
  1517→        .only
  1518→        .map(|it| it.into_iter().filter_map(from_proto::assist_kind).collect());
  1519→
  1520→    let (assist_index, assist_resolve) = match parse_action_id(&params.id) {
  1521→        Ok(parsed_data) => parsed_data,
  1522→        Err(e) => {
  1523→            return Err(invalid_params_error(format!(
  1524→                "Failed to parse action id string '{}': {e}",
  1525→                params.id
  1526→            ))
  1527→            .into());
  1528→        }
  1529→    };
  1530→
  1531→    let expected_assist_id = assist_resolve.assist_id.clone();
  1532→    let expected_kind = assist_resolve.assist_kind;
  1533→
  1534→    let assists = snap.analysis.assists_with_fixes(
  1535→        &assists_config,
  1536→        &snap.config.diagnostic_fixes(Some(source_root)),
  1537→        AssistResolveStrategy::Single(assist_resolve),
  1538→        frange,
  1539→    )?;
  1540→
  1541→    let assist = match assists.get(assist_index) {
  1542→        Some(assist) => assist,
  1543→        None => return Err(invalid_params_error(format!(
  1544→            "Failed to find the assist for index {} provided by the resolve request. Resolve request assist id: {}",
  1545→            assist_index, params.id,
  1546→        ))
  1547→        .into())
  1548→    };
  1549→    if assist.id.0 != expected_assist_id || assist.id.1 != expected_kind {
  1550→        return Err(invalid_params_error(format!(
  1551→            "Mismatching assist at index {} for the resolve parameters given. Resolve request assist id: {}, actual id: {:?}.",
  1552→            assist_index, params.id, assist.id
  1553→        ))
  1554→        .into());
  1555→    }
  1556→    let ca = to_proto::code_action(&snap, assist.clone(), None)?;
  1557→    code_action.edit = ca.edit;
  1558→    code_action.command = ca.command;
  1559→
  1560→    if let Some(edit) = code_action.edit.as_ref() {
  1561→        if let Some(changes) = edit.document_changes.as_ref() {
  1562→            for change in changes {
  1563→                if let lsp_ext::SnippetDocumentChangeOperation::Op(res_op) = change {
  1564→                    resource_ops_supported(&snap.config, resolve_resource_op(res_op))?
  1565→                }
  1566→            }
  1567→        }
  1568→    }
  1569→
  1570→    Ok(code_action)
  1571→}
  1572→
  1573→fn parse_action_id(action_id: &str) -> anyhow::Result<(usize, SingleResolve), String> {
  1574→    let id_parts = action_id.split(':').collect::<Vec<_>>();
  1575→    match id_parts.as_slice() {
  1576→        [assist_id_string, assist_kind_string, index_string, subtype_str] => {
  1577→            let assist_kind: AssistKind = assist_kind_string.parse()?;
  1578→            let index: usize = match index_string.parse() {
  1579→                Ok(index) => index,
  1580→                Err(e) => return Err(format!("Incorrect index string: {e}")),
  1581→            };
  1582→            let assist_subtype = subtype_str.parse::<usize>().ok();
  1583→            Ok((
  1584→                index,
  1585→                SingleResolve {
  1586→                    assist_id: assist_id_string.to_string(),
  1587→                    assist_kind,
  1588→                    assist_subtype,
  1589→                },
  1590→            ))
  1591→        }
  1592→        _ => Err("Action id contains incorrect number of segments".to_owned()),
  1593→    }
  1594→}
