  1596→pub(crate) fn handle_code_lens(
  1597→    snap: GlobalStateSnapshot,
  1598→    params: lsp_types::CodeLensParams,
  1599→) -> anyhow::Result<Option<Vec<CodeLens>>> {
  1600→    let _p = tracing::info_span!("handle_code_lens").entered();
  1601→
  1602→    let lens_config = snap.config.lens();
  1603→    if lens_config.none() {
  1604→        // early return before any db query!
  1605→        return Ok(Some(Vec::default()));
  1606→    }
  1607→
  1608→    let file_id = try_default!(from_proto::file_id(&snap, &params.text_document.uri)?);
  1609→    let target_spec = TargetSpec::for_file(&snap, file_id)?;
  1610→
  1611→    let annotations = snap.analysis.annotations(
  1612→        &AnnotationConfig {
  1613→            binary_target: target_spec
  1614→                .map(|spec| {
  1615→                    matches!(
  1616→                        spec.target_kind(),
  1617→                        TargetKind::Bin | TargetKind::Example | TargetKind::Test
  1618→                    )
  1619→                })
  1620→                .unwrap_or(false),
  1621→            annotate_runnables: lens_config.runnable(),
  1622→            annotate_impls: lens_config.implementations,
  1623→            annotate_references: lens_config.refs_adt,
  1624→            annotate_method_references: lens_config.method_refs,
  1625→            annotate_enum_variant_references: lens_config.enum_variant_refs,
  1626→            location: lens_config.location.into(),
  1627→        },
  1628→        file_id,
  1629→    )?;
  1630→
  1631→    let mut res = Vec::new();
  1632→    for a in annotations {
  1633→        to_proto::code_lens(&mut res, &snap, a)?;
  1634→    }
  1635→
  1636→    Ok(Some(res))
  1637→}
  1638→
  1639→pub(crate) fn handle_code_lens_resolve(
  1640→    snap: GlobalStateSnapshot,
  1641→    mut code_lens: CodeLens,
  1642→) -> anyhow::Result<CodeLens> {
  1643→    let Some(data) = code_lens.data.take() else {
  1644→        return Ok(code_lens);
  1645→    };
  1646→    let resolve = serde_json::from_value::<lsp_ext::CodeLensResolveData>(data)?;
  1647→    let Some(annotation) = from_proto::annotation(&snap, code_lens.range, resolve)? else {
  1648→        return Ok(code_lens);
  1649→    };
  1650→    let annotation = snap.analysis.resolve_annotation(annotation)?;
  1651→
  1652→    let mut acc = Vec::new();
  1653→    to_proto::code_lens(&mut acc, &snap, annotation)?;
  1654→
  1655→    let mut res = match acc.pop() {
  1656→        Some(it) if acc.is_empty() => it,
  1657→        _ => {
  1658→            never!();
  1659→            code_lens
  1660→        }
  1661→    };
  1662→    res.data = None;
  1663→
  1664→    Ok(res)
  1665→}
