  1716→pub(crate) fn handle_inlay_hints(
  1717→    snap: GlobalStateSnapshot,
  1718→    params: InlayHintParams,
  1719→) -> anyhow::Result<Option<Vec<InlayHint>>> {
  1720→    let _p = tracing::info_span!("handle_inlay_hints").entered();
  1721→    let document_uri = &params.text_document.uri;
  1722→    let FileRange { file_id, range } = try_default!(from_proto::file_range(
  1723→        &snap,
  1724→        &TextDocumentIdentifier::new(document_uri.to_owned()),
  1725→        params.range,
  1726→    )?);
  1727→    let line_index = snap.file_line_index(file_id)?;
  1728→    let range = TextRange::new(
  1729→        range.start().min(line_index.index.len()),
  1730→        range.end().min(line_index.index.len()),
  1731→    );
  1732→
  1733→    let inlay_hints_config = snap.config.inlay_hints();
  1734→    Ok(Some(
  1735→        snap.analysis
  1736→            .inlay_hints(&inlay_hints_config, file_id, Some(range))?
  1737→            .into_iter()
  1738→            .map(|it| {
  1739→                to_proto::inlay_hint(
  1740→                    &snap,
  1741→                    &inlay_hints_config.fields_to_resolve,
  1742→                    &line_index,
  1743→                    file_id,
  1744→                    it,
  1745→                )
  1746→            })
  1747→            .collect::<Cancellable<Vec<_>>>()?,
  1748→    ))
  1749→}
  1750→
  1751→pub(crate) fn handle_inlay_hints_resolve(
  1752→    snap: GlobalStateSnapshot,
  1753→    mut original_hint: InlayHint,
  1754→) -> anyhow::Result<InlayHint> {
  1755→    let _p = tracing::info_span!("handle_inlay_hints_resolve").entered();
  1756→
  1757→    let Some(data) = original_hint.data.take() else {
  1758→        return Ok(original_hint);
  1759→    };
  1760→    let resolve_data: lsp_ext::InlayHintResolveData = serde_json::from_value(data)?;
  1761→    let file_id = FileId::from_raw(resolve_data.file_id);
  1762→    if resolve_data.version != snap.file_version(file_id) {
  1763→        tracing::warn!("Inlay hint resolve data is outdated");
  1764→        return Ok(original_hint);
  1765→    }
  1766→    let Some(hash) = resolve_data.hash.parse().ok() else {
  1767→        return Ok(original_hint);
  1768→    };
  1769→    anyhow::ensure!(snap.file_exists(file_id), "Invalid LSP resolve data");
  1770→
  1771→    let line_index = snap.file_line_index(file_id)?;
  1772→    let range = from_proto::text_range(&line_index, resolve_data.resolve_range)?;
  1773→
  1774→    let mut forced_resolve_inlay_hints_config = snap.config.inlay_hints();
  1775→    forced_resolve_inlay_hints_config.fields_to_resolve = InlayFieldsToResolve::empty();
  1776→    let resolve_hints = snap.analysis.inlay_hints_resolve(
  1777→        &forced_resolve_inlay_hints_config,
  1778→        file_id,
  1779→        range,
  1780→        hash,
  1781→        |hint| {
  1782→            std::hash::BuildHasher::hash_one(
  1783→                &std::hash::BuildHasherDefault::<ide_db::FxHasher>::default(),
  1784→                hint,
  1785→            )
  1786→        },
  1787→    )?;
  1788→
  1789→    Ok(resolve_hints
  1790→        .and_then(|it| {
  1791→            to_proto::inlay_hint(
  1792→                &snap,
  1793→                &forced_resolve_inlay_hints_config.fields_to_resolve,
  1794→                &line_index,
  1795→                file_id,
  1796→                it,
  1797→            )
  1798→            .ok()
  1799→        })
  1800→        .filter(|hint| hint.position == original_hint.position)
  1801→        .filter(|hint| hint.kind == original_hint.kind)
  1802→        .unwrap_or(original_hint))
  1803→}
