  1828→pub(crate) fn handle_call_hierarchy_incoming(
  1829→    snap: GlobalStateSnapshot,
  1830→    params: CallHierarchyIncomingCallsParams,
  1831→) -> anyhow::Result<Option<Vec<CallHierarchyIncomingCall>>> {
  1832→    let _p = tracing::info_span!("handle_call_hierarchy_incoming").entered();
  1833→    let item = params.item;
  1834→
  1835→    let doc = TextDocumentIdentifier::new(item.uri);
  1836→    let frange = try_default!(from_proto::file_range(&snap, &doc, item.selection_range)?);
  1837→    let fpos = FilePosition { file_id: frange.file_id, offset: frange.range.start() };
  1838→
  1839→    let config = snap.config.call_hierarchy();
  1840→    let call_items = match snap.analysis.incoming_calls(config, fpos)? {
  1841→        None => return Ok(None),
  1842→        Some(it) => it,
  1843→    };
  1844→
  1845→    let mut res = vec![];
  1846→
  1847→    for call_item in call_items.into_iter() {
  1848→        let file_id = call_item.target.file_id;
  1849→        let line_index = snap.file_line_index(file_id)?;
  1850→        let item = to_proto::call_hierarchy_item(&snap, call_item.target)?;
  1851→        res.push(CallHierarchyIncomingCall {
  1852→            from: item,
  1853→            from_ranges: call_item
  1854→                .ranges
  1855→                .into_iter()
  1856→                // This is the range relative to the item
  1857→                .filter(|it| it.file_id == file_id)
  1858→                .map(|it| to_proto::range(&line_index, it.range))
  1859→                .collect(),
  1860→        });
  1861→    }
  1862→
  1863→    Ok(Some(res))
  1864→}
