  1866→pub(crate) fn handle_call_hierarchy_outgoing(
  1867→    snap: GlobalStateSnapshot,
  1868→    params: CallHierarchyOutgoingCallsParams,
  1869→) -> anyhow::Result<Option<Vec<CallHierarchyOutgoingCall>>> {
  1870→    let _p = tracing::info_span!("handle_call_hierarchy_outgoing").entered();
  1871→    let item = params.item;
  1872→
  1873→    let doc = TextDocumentIdentifier::new(item.uri);
  1874→    let frange = try_default!(from_proto::file_range(&snap, &doc, item.selection_range)?);
  1875→    let fpos = FilePosition { file_id: frange.file_id, offset: frange.range.start() };
  1876→    let line_index = snap.file_line_index(fpos.file_id)?;
  1877→
  1878→    let config = snap.config.call_hierarchy();
  1879→    let call_items = match snap.analysis.outgoing_calls(config, fpos)? {
  1880→        None => return Ok(None),
  1881→        Some(it) => it,
  1882→    };
  1883→
  1884→    let mut res = vec![];
  1885→
  1886→    for call_item in call_items.into_iter() {
  1887→        let item = to_proto::call_hierarchy_item(&snap, call_item.target)?;
  1888→        res.push(CallHierarchyOutgoingCall {
  1889→            to: item,
  1890→            from_ranges: call_item
  1891→                .ranges
  1892→                .into_iter()
  1893→                // This is the range relative to the caller
  1894→                .filter(|it| it.file_id == fpos.file_id)
  1895→                .map(|it| to_proto::range(&line_index, it.range))
  1896→                .collect(),
  1897→        });
