  1903→pub(crate) fn handle_semantic_tokens_full(
  1904→    snap: GlobalStateSnapshot,
  1905→    params: SemanticTokensParams,
  1906→) -> anyhow::Result<Option<SemanticTokensResult>> {
  1907→    let _p = tracing::info_span!("handle_semantic_tokens_full").entered();
  1908→
  1909→    let file_id = try_default!(from_proto::file_id(&snap, &params.text_document.uri)?);
  1910→    let text = snap.analysis.file_text(file_id)?;
  1911→    let line_index = snap.file_line_index(file_id)?;
  1912→
  1913→    let mut highlight_config = snap.config.highlighting_config();
  1914→    // Avoid flashing a bunch of unresolved references when the proc-macro servers haven't been spawned yet.
  1915→    highlight_config.syntactic_name_ref_highlighting =
  1916→        snap.workspaces.is_empty() || !snap.proc_macros_loaded;
  1917→
  1918→    let highlights = snap.analysis.highlight(highlight_config, file_id)?;
  1919→    let semantic_tokens = to_proto::semantic_tokens(
  1920→        &text,
  1921→        &line_index,
  1922→        highlights,
  1923→        snap.config.semantics_tokens_augments_syntax_tokens(),
  1924→        snap.config.highlighting_non_standard_tokens(),
  1925→    );
  1926→
  1927→    // Unconditionally cache the tokens
  1928→    snap.semantic_tokens_cache.lock().insert(params.text_document.uri, semantic_tokens.clone());
  1929→
  1930→    Ok(Some(semantic_tokens.into()))
  1931→}
  1932→
  1933→pub(crate) fn handle_semantic_tokens_full_delta(
  1934→    snap: GlobalStateSnapshot,
  1935→    params: SemanticTokensDeltaParams,
  1936→) -> anyhow::Result<Option<SemanticTokensFullDeltaResult>> {
  1937→    let _p = tracing::info_span!("handle_semantic_tokens_full_delta").entered();
  1938→
  1939→    let file_id = try_default!(from_proto::file_id(&snap, &params.text_document.uri)?);
  1940→    let text = snap.analysis.file_text(file_id)?;
  1941→    let line_index = snap.file_line_index(file_id)?;
