  1943→    let mut highlight_config = snap.config.highlighting_config();
  1944→    // Avoid flashing a bunch of unresolved references when the proc-macro servers haven't been spawned yet.
  1945→    highlight_config.syntactic_name_ref_highlighting =
  1946→        snap.workspaces.is_empty() || !snap.proc_macros_loaded;
  1947→
  1948→    let highlights = snap.analysis.highlight(highlight_config, file_id)?;
  1949→    let semantic_tokens = to_proto::semantic_tokens(
  1950→        &text,
  1951→        &line_index,
  1952→        highlights,
  1953→        snap.config.semantics_tokens_augments_syntax_tokens(),
  1954→        snap.config.highlighting_non_standard_tokens(),
  1955→    );
  1956→
  1957→    let cached_tokens = snap.semantic_tokens_cache.lock().remove(&params.text_document.uri);
  1958→
  1959→    if let Some(cached_tokens @ lsp_types::SemanticTokens { result_id: Some(prev_id), .. }) =
  1960→        &cached_tokens
  1961→    {
  1962→        if *prev_id == params.previous_result_id {
  1963→            let delta = to_proto::semantic_token_delta(cached_tokens, &semantic_tokens);
  1964→            snap.semantic_tokens_cache.lock().insert(params.text_document.uri, semantic_tokens);
  1965→            return Ok(Some(delta.into()));
  1966→        }
  1967→    }
  1968→
  1969→    // Clone first to keep the lock short
  1970→    let semantic_tokens_clone = semantic_tokens.clone();
  1971→    snap.semantic_tokens_cache.lock().insert(params.text_document.uri, semantic_tokens_clone);
  1972→
  1973→    Ok(Some(semantic_tokens.into()))
  1974→}
